-- ----------------------------------------------------------
-- Metadata
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS wirbel_metadata (
    id                  SERIAL PRIMARY KEY,
    sample_name         VARCHAR(100) NOT NULL UNIQUE,
    study_name          VARCHAR(100) NOT NULL,
    sample_id           VARCHAR(100) NOT NULL,
    subject_id          VARCHAR(100) NOT NULL,
    body_site           VARCHAR(50)  NOT NULL,
    study_condition     VARCHAR(50)  NOT NULL,
    disease             VARCHAR(50)  NOT NULL,
    age                 INT          NOT NULL,
    age_category        VARCHAR(20)  NOT NULL,
    gender              VARCHAR(20)  NOT NULL,
    country             VARCHAR(10)  NOT NULL,
    non_westernized     BOOLEAN      NOT NULL,
    sequencing_platform VARCHAR(50)  NOT NULL,
    dna_extraction_kit  VARCHAR(50)  NOT NULL,
    pmid                INT          NOT NULL,
    number_reads        BIGINT       NOT NULL,
    number_bases        BIGINT       NOT NULL,
    minimum_read_length INT          NOT NULL,
    median_read_length  INT          NOT NULL,
    curator             VARCHAR(100) NOT NULL,
    bmi                 FLOAT        NOT NULL,
    patient_num         VARCHAR(20)  NOT NULL
);

