-- ----------------------------------------------------------
-- Taxa abundance
-- ----------------------------------------------------------
CREATE TABLE IF NOT EXISTS wirbel_taxa (
    id          SERIAL PRIMARY KEY,
    sample_name VARCHAR(100) NOT NULL REFERENCES wirbel_metadata(sample_name),
    class       VARCHAR(50)  NOT NULL,
    faecalibacterium_prausnitzii FLOAT NOT NULL DEFAULT 0,
    bacteroides_uniformis FLOAT NOT NULL DEFAULT 0,
    alistipes_putredinis FLOAT NOT NULL DEFAULT 0,
    phocaeicola_vulgatus FLOAT NOT NULL DEFAULT 0,
    roseburia_intestinalis FLOAT NOT NULL DEFAULT 0,
    roseburia_inulinivorans FLOAT NOT NULL DEFAULT 0,
    fusicatenibacter_saccharivorans FLOAT NOT NULL DEFAULT 0,
    collinsella_aerofaciens FLOAT NOT NULL DEFAULT 0,
    x_eubacterium_rectale FLOAT NOT NULL DEFAULT 0,
    bifidobacterium_adolescentis FLOAT NOT NULL DEFAULT 0,
    eubacterium_sp_cag_38 FLOAT NOT NULL DEFAULT 0,
    alistipes_finegoldii FLOAT NOT NULL DEFAULT 0,
    bacteroides_stercoris FLOAT NOT NULL DEFAULT 0,
    ruminococcus_bromii FLOAT NOT NULL DEFAULT 0,
    bacteroides_faecis_cag_32 FLOAT NOT NULL DEFAULT 0,
    parabacteroides_merdae FLOAT NOT NULL DEFAULT 0,
    bifidobacterium_longum FLOAT NOT NULL DEFAULT 0,
    bacteroides_faecis FLOAT NOT NULL DEFAULT 0,
    odoribacter_splanchnicus FLOAT NOT NULL DEFAULT 0,
    lachnospira_eligens FLOAT NOT NULL DEFAULT 0,
    dorea_longicatena FLOAT NOT NULL DEFAULT 0,
